 59→  const visibleInspection = inspection && sceneDescriptor.visibleFloorIds.includes(inspection.floorId)
 60→    ? inspection
 61→    : null;
 62→  const handlePreviewScopeChange = useCallback((nextScope) => {
 63→    setPreviewScope(nextScope);
 64→
 65→    if (nextScope === 'all') return;
 66→    if (!orderedFloors.some((floor) => floor.id === nextScope)) return;
 67→    if (nextScope !== activeFloorId) {
 68→      editorDispatch({ type: 'SET_ACTIVE_FLOOR', floorId: nextScope });
 69→    }
 70→  }, [activeFloorId, editorDispatch, orderedFloors]);
 71→  const handlePreviewPick = useCallback((target) => {
 72→    if (!target?.sourceId || !target?.kind) {
 73→      editorDispatch({ type: 'DESELECT' });
 74→      return;
 75→    }
 76→
 77→    if (target.floorId && target.floorId !== activeFloorId) {
 78→      editorDispatch({ type: 'SET_ACTIVE_FLOOR', floorId: target.floorId });
 79→    }
 80→
 81→    editorDispatch({ type: 'SELECT_OBJECT', id: target.sourceId, objectType: target.kind });
 82→  }, [activeFloorId, editorDispatch]);
 83→
 84→  useEffect(() => {
 85→    if (!containerRef.current) return undefined;
 86→
 87→    const viewport = createPreviewViewport(containerRef.current);
 88→    viewportRef.current = viewport;
 89→
 90→    if ('ResizeObserver' in window) {
 91→      const observer = new ResizeObserver(() => {
 92→        viewport.resize();
 93→      });
 94→      observer.observe(containerRef.current);
 95→      resizeObserverRef.current = observer;
 96→    }
 97→
 98→    viewport.resize();
 99→
100→    return () => {
101→      resizeObserverRef.current?.disconnect?.();
102→      resizeObserverRef.current = null;
103→      viewport.dispose();
104→      viewportRef.current = null;
105→    };
106→  }, []);
107→
108→  useEffect(() => {
109→    viewportRef.current?.setPickHandler(handlePreviewPick);
110→  }, [handlePreviewPick]);
111→
112→  useEffect(() => {
113→    viewportRef.current?.setPickContext({ activeFloorId });
114→  }, [activeFloorId]);
115→
116→  useEffect(() => {
117→    viewportRef.current?.setWalkUiHandler(setWalkUiState);
118→    viewportRef.current?.setWalkExitHandler(() => {
119→      setNavigationMode('inspect');
120→    });
121→  }, []);
122→
123→  useEffect(() => {
124→    viewportRef.current?.setCompassHeadingHandler((headingDeg) => {
125→      if (!compassNeedleRef.current) return;
