127→    });
128→
129→    return () => {
130→      viewportRef.current?.setCompassHeadingHandler(null);
131→    };
132→  }, []);
133→
134→  useEffect(() => {
135→    const viewport = viewportRef.current;
136→    if (!viewport) return;
137→
138→    const root = buildPreviewObjectRoot(sceneDescriptor, viewport.materialPalette, {
139→      selectedId,
140→      selectedType,
141→    });
142→    viewport.setWorld(root, sceneDescriptor.bounds, sceneDescriptor.groundLevel);
143→  }, [sceneDescriptor, selectedId, selectedType]);
144→
145→  useEffect(() => {
146→    viewportRef.current?.setNavigationMode(navigationMode);
147→  }, [navigationMode]);
148→
149→  useEffect(() => {
150→    viewportRef.current?.setActiveFloorContext(walkFloorContext);
151→  }, [walkFloorContext]);
152→
153→  const resetLabel = navigationMode === 'walk' ? 'Reset Walk' : 'Reset View';
154→  const primaryFooter = navigationMode === 'walk'
155→    ? (walkUiState.isLocked
