158→    : 'Orbit: drag · Pan: right drag · Zoom: wheel · Inspect: click object';
159→  const secondaryFooter = navigationMode === 'walk'
160→    ? 'Ghost walk is noclip flight now, still read-only and collision-free.'
161→    : 'Perspective preview, future-ready for presets and floor visibility.';
162→
163→  return (
164→    <section className={`${styles.panel} ${className}`}>
165→      <div className={styles.header}>
166→        <div className={styles.titleGroup}>
167→          <span className={styles.eyebrow}>3D Preview</span>
168→          <span className={styles.title}>
