  1→import { buildElevationAnnotationScene } from '@/elevations/annotations';
  2→import { buildProjectElevationScene } from '@/elevations/scene';
  3→import { getDefaultActiveFloorId, resolveProjectFloor } from '@/domain/floorModels';
  4→import { filterFloorByPhase, filterProjectByPhase } from '@/domain/phaseFilter';
  5→import { getBeamRenderData } from '@/geometry/beamGeometry';
  6→import { columnOutline } from '@/geometry/columnGeometry';
  7→import { landingOutline } from '@/geometry/landingGeometry';
  8→import { getSectionCutRenderData } from '@/geometry/sectionCutGeometry';
  9→import { getSlabRenderData } from '@/geometry/slabGeometry';
 10→import { getStairRenderData } from '@/geometry/stairGeometry';
 11→import { fixtureOutline } from '@/geometry/fixtureGeometry';
 12→import { doorOutlineOnWall, windowOutlineOnWall } from '@/geometry/wallGeometry';
 13→import { getWallRenderData } from '@/geometry/wallColumnGeometry';
 14→import { buildProjectSectionScene } from '@/sections/scene';
 15→
 16→const PLAN_PADDING = 1500;
 17→const VERTICAL_PADDING = 700;
 18→const TOP_PADDING = 1100;
 19→
 20→function boundsFromPoints(points = [], fallback = { minX: -1000, maxX: 1000, minY: -1000, maxY: 1000 }) {
 21→  if (!points.length) return fallback;
 22→  return {
 23→    minX: Math.min(...points.map((point) => point.x)),
 24→    maxX: Math.max(...points.map((point) => point.x)),
 25→    minY: Math.min(...points.map((point) => point.y)),
 26→    maxY: Math.max(...points.map((point) => point.y)),
 27→  };
 28→}
 29→
 30→function expandBounds(bounds, paddingX, paddingY = paddingX) {
 31→  return {
 32→    minX: bounds.minX - paddingX,
 33→    maxX: bounds.maxX + paddingX,
 34→    minY: bounds.minY - paddingY,
 35→    maxY: bounds.maxY + paddingY,
 36→  };
 37→}
 38→
 39→function collectPlanPoints(floor) {
 40→  const points = [];
 41→
 42→  for (const wall of floor.walls || []) {
 43→    points.push(...(getWallRenderData(wall, floor.columns || []).outline || []));
 44→  }
 45→  for (const room of floor.rooms || []) {
 46→    points.push(...(room.points || []));
 47→  }
 48→  for (const beam of floor.beams || []) {
 49→    const renderData = getBeamRenderData(beam, floor.columns || []);
 50→    if (renderData?.outline) points.push(...renderData.outline);
 51→  }
 52→  for (const stair of floor.stairs || []) {
 53→    const renderData = getStairRenderData(stair);
 54→    if (renderData?.outline) points.push(...renderData.outline);
 55→  }
 56→  for (const landing of floor.landings || []) {
 57→    points.push(...landingOutline(landing));
 58→  }
 59→  for (const column of floor.columns || []) {
 60→    points.push(...columnOutline(column));
 61→  }
 62→  for (const slab of (floor.slabs || [])) {
 63→    const rd = getSlabRenderData(slab);
 64→    if (rd?.boundaryPoints) points.push(...rd.boundaryPoints);
 65→  }
 66→  for (const sc of (floor.sectionCuts || [])) {
 67→    points.push(sc.startPoint, sc.endPoint);
 68→    const renderData = getSectionCutRenderData(sc);
 69→    if (renderData?.arrow) {
 70→      points.push(renderData.arrow.shaftStart, renderData.arrow.shaftEnd, renderData.arrow.headA, renderData.arrow.headB);
 71→    }
 72→  }
 73→
 74→  for (const door of floor.doors || []) {
 75→    const wall = (floor.walls || []).find((entry) => entry.id === door.wallId);
 76→    if (!wall) continue;
 77→    const outline = doorOutlineOnWall(wall, door);
 78→    points.push(outline.p1, outline.p2, outline.p3, outline.p4);
 79→  }
 80→
 81→  for (const windowItem of floor.windows || []) {
 82→    const wall = (floor.walls || []).find((entry) => entry.id === windowItem.wallId);
 83→    if (!wall) continue;
 84→    const outline = windowOutlineOnWall(wall, windowItem);
 85→    points.push(outline.p1, outline.p2, outline.p3, outline.p4);
 86→  }
 87→
 88→  for (const fixture of floor.fixtures || []) {
 89→    points.push(...fixtureOutline(fixture));
 90→  }
 91→
 92→  return points;
 93→}
 94→
 95→function buildPlanSource(floor) {
 96→  if (!floor) {
 97→    return {
 98→      kind: 'empty',
 99→      title: 'Plan',
100→      message: 'Missing floor.',
101→      bounds: { minX: 0, maxX: 2000, minY: 0, maxY: 1500 },
102→    };
103→  }
104→
105→  const geometryBounds = expandBounds(boundsFromPoints(collectPlanPoints(floor)), PLAN_PADDING);
106→
107→  return {
108→    kind: 'plan',
109→    title: `${floor.name} Plan`,
110→    floor,
111→    bounds: geometryBounds,
112→  };
113→}
114→
115→function sceneBoundsToRenderBounds(scene) {
116→  return {
117→    minX: scene.bounds.minX - VERTICAL_PADDING,
118→    maxX: scene.bounds.maxX + VERTICAL_PADDING,
119→    minY: -scene.bounds.maxZ - TOP_PADDING,
120→    maxY: -scene.bounds.minZ + VERTICAL_PADDING,
121→  };
122→}
123→
124→function buildSectionSource(project, floor, sourceRefId) {
125→  const cuts = floor?.sectionCuts || [];
126→  const sectionCut = sourceRefId
127→    ? cuts.find(s => s.id === sourceRefId)
128→    : cuts[0] || null;
129→
130→  if (!sectionCut) {
131→    return {
132→      kind: 'empty',
133→      title: 'Section',
134→      message: 'No section cut on this floor.',
135→      bounds: { minX: 0, maxX: 2000, minY: -3000, maxY: 1000 },
136→    };
137→  }
138→
139→  const scene = buildProjectSectionScene(project, floor.id, sectionCut.id);
140→  return {
141→    kind: 'section',
142→    title: sectionCut.label || 'Section',
143→    floor,
144→    scene,
145→    bounds: sceneBoundsToRenderBounds(scene),
146→  };
147→}
148→
149→function buildElevationSource(project, floor, sourceView) {
150→  if (!floor) {
151→    return {
152→      kind: 'empty',
153→      title: 'Elevation',
154→      message: 'Missing floor.',
155→      bounds: { minX: 0, maxX: 2000, minY: -3000, maxY: 1000 },
156→    };
157→  }
158→
159→  const scene = buildProjectElevationScene(project, floor.id, sourceView);
160→  const annotationScene = buildElevationAnnotationScene(floor, scene);
161→
162→  return {
163→    kind: 'elevation',
164→    title: scene.title,
165→    floor,
166→    viewMode: sourceView,
167→    scene,
168→    annotationScene,
169→    bounds: sceneBoundsToRenderBounds(scene),
170→  };
171→}
172→
173→function build3DPreviewSource(project, floor) {
174→  if (!floor) {
175→    return {
176→      kind: 'empty',
177→      title: 'Axonometric View',
178→      message: 'Missing floor.',
179→      bounds: { minX: 0, maxX: 2000, minY: 0, maxY: 1500 },
180→    };
181→  }
182→
183→  // Use 16:10 aspect ratio matching render resolution (1600x1000).
184→  // At scale 100, this fills a 160x100mm viewport on paper.
185→  const imageWidth = 16000;
186→  const imageHeight = 10000;
187→
188→  return {
189→    kind: '3d_preview',
190→    title: 'Axonometric View',
191→    project,
192→    activeFloorId: floor.id,
193→    bounds: {
194→      minX: 0,
195→      maxX: imageWidth,
196→      minY: 0,
197→      maxY: imageHeight,
198→    },
199→  };
200→}
201→
202→export function resolveSheetViewportSource(project, viewport, phaseContext) {
203→  const defaultFloorId = getDefaultActiveFloorId(project, viewport.sourceFloorId);
204→  let effectiveProject = project;
205→  let floor = resolveProjectFloor(project, defaultFloorId);
206→
207→  if (phaseContext?.activePhaseId && phaseContext?.phaseViewMode && phaseContext.phaseViewMode !== 'all') {
208→    effectiveProject = filterProjectByPhase(project, phaseContext.activePhaseId, phaseContext.phaseViewMode);
209→    floor = resolveProjectFloor(effectiveProject, defaultFloorId);
210→  }
211→
212→  switch (viewport.sourceView) {
213→    case '3d_preview':
214→      return build3DPreviewSource(effectiveProject, floor);
215→    case 'section':
216→      return buildSectionSource(effectiveProject, floor, viewport.sourceRefId);
217→    case 'elevation_front':
218→    case 'elevation_rear':
219→    case 'elevation_left':
220→    case 'elevation_right':
221→      return buildElevationSource(effectiveProject, floor, viewport.sourceView);
222→    case 'plan':
223→    default:
224→      return buildPlanSource(floor);
225→  }
226→}
227→
228→export function getViewportSourceLabel(sourceView) {
229→  switch (sourceView) {
230→    case '3d_preview':
231→      return 'Axonometric View';
232→    case 'section':
233→      return 'Section';
234→    case 'elevation_front':
235→      return 'Front Elevation';
236→    case 'elevation_rear':
237→      return 'Rear Elevation';
238→    case 'elevation_left':
239→      return 'Left Elevation';
240→    case 'elevation_right':
241→      return 'Right Elevation';
242→    case 'plan':
243→    default:
244→      return 'Plan';
245→  }
246→}
