 20→function boundsFromPoints(points = [], fallback = { minX: -1000, maxX: 1000, minY: -1000, maxY: 1000 }) {
 21→  if (!points.length) return fallback;
 22→  return {
 23→    minX: Math.min(...points.map((point) => point.x)),
 24→    maxX: Math.max(...points.map((point) => point.x)),
 25→    minY: Math.min(...points.map((point) => point.y)),
 26→    maxY: Math.max(...points.map((point) => point.y)),
 27→  };
 28→}
 29→
 30→function expandBounds(bounds, paddingX, paddingY = paddingX) {
 31→  return {
 32→    minX: bounds.minX - paddingX,
 33→    maxX: bounds.maxX + paddingX,
 34→    minY: bounds.minY - paddingY,
 35→    maxY: bounds.maxY + paddingY,
 36→  };
 37→}
