39→export function getViewportRotationHandle(viewport, handleSize) {
40→  const cx = viewport.x + viewport.width / 2;
41→  const stemLength = handleSize * 2.5;
42→  const radius = handleSize / 2;
43→  const stemY1 = viewport.y;
44→  const stemY2 = viewport.y - stemLength;
45→  const cy = stemY2 - radius;
46→  return { cx, cy, radius, stemX: cx, stemY1, stemY2 };
47→}
48→
49→export function hitTestViewportRotationHandle(point, viewport, handleSize) {
50→  const { cx, cy, radius } = getViewportRotationHandle(viewport, handleSize);
51→  const dx = point.x - cx;
52→  const dy = point.y - cy;
53→  return dx * dx + dy * dy <= (radius + handleSize * 0.3) * (radius + handleSize * 0.3);
54→}
