146→            {isSelected && Object.values(getViewportHandleRects(viewport, HANDLE_SIZE)).map((handleRect) => (
147→              <rect
148→                key={`${viewport.id}-${handleRect.x}-${handleRect.y}`}
149→                x={handleRect.x}
150→                y={handleRect.y}
151→                width={handleRect.width}
152→                height={handleRect.height}
153→                fill="#ffffff"
154→                stroke="#0f8f74"
155→                strokeWidth={0.5}
156→              />
157→            ))}
158→            {isSelected && (() => {
159→              const rh = getViewportRotationHandle(viewport, HANDLE_SIZE);
160→              return (
161→                <>
162→                  <line
163→                    x1={rh.stemX}
164→                    y1={rh.stemY1}
165→                    x2={rh.stemX}
166→                    y2={rh.stemY2}
167→                    stroke="#0f8f74"
168→                    strokeWidth={0.4}
169→                  />
170→                  <circle
171→                    cx={rh.cx}
172→                    cy={rh.cy}
173→                    r={rh.radius}
174→                    fill="#ffffff"
175→                    stroke="#0f8f74"
176→                    strokeWidth={0.5}
177→                    style={{ cursor: 'grab' }}
178→                  />
179→                </>
180→              );
181→            })()}
182→          </g>
183→        );
184→      })}
185→    </g>
