 85→function ThreePreviewViewportContent({ source }) {
 86→  const [previewState, setPreviewState] = useState({
 87→    status: 'loading',
 88→    imageUrl: null,
 89→  });
 90→
 91→  useEffect(() => {
 92→    if (!source?.project) {
 93→      setPreviewState({
 94→        status: 'empty',
 95→        imageUrl: null,
 96→      });
 97→      return undefined;
 98→    }
 99→
100→    let cancelled = false;
101→    setPreviewState({
102→      status: 'loading',
103→      imageUrl: null,
104→    });
105→
106→    renderSheetPreviewImage(source)
107→      .then((result) => {
108→        if (cancelled) return;
109→        setPreviewState(result);
110→      })
111→      .catch((error) => {
112→        if (cancelled) return;
113→        console.error('Failed to render sheet 3D preview:', error);
114→        setPreviewState({
115→          status: 'error',
116→          imageUrl: null,
117→        });
118→      });
119→
120→    return () => { cancelled = true; };
121→  }, [source?.project, source?.project?.updatedAt, source?.activeFloorId]);
122→
123→  const { bounds } = source;
124→  const centerX = (bounds.minX + bounds.maxX) / 2;
125→  const centerY = (bounds.minY + bounds.maxY) / 2;
126→
127→  if (previewState.status !== 'ready' || !previewState.imageUrl) {
128→    const messages = {
129→      loading: 'Rendering 3D preview...',
130→      empty: 'No 3D geometry available.',
131→      error: '3D preview failed to render.',
132→    };
133→
134→    return (
135→      <text
136→        x={centerX}
137→        y={centerY}
138→        textAnchor="middle"
139→        fontSize={400}
140→        fill="#8899aa"
141→        pointerEvents="none"
142→      >
143→        {messages[previewState.status] || messages.loading}
144→      </text>
145→    );
146→  }
147→
148→  return (
149→    <image
150→      href={previewState.imageUrl}
151→      x={bounds.minX}
152→      y={bounds.minY}
153→      width={bounds.maxX - bounds.minX}
154→      height={bounds.maxY - bounds.minY}
155→      preserveAspectRatio="xMidYMid meet"
156→      pointerEvents="none"
157→    />
158→  );
