 95→function buildPlanSource(floor) {
 96→  if (!floor) {
 97→    return {
 98→      kind: 'empty',
 99→      title: 'Plan',
100→      message: 'Missing floor.',
101→      bounds: { minX: 0, maxX: 2000, minY: 0, maxY: 1500 },
102→    };
103→  }
104→
105→  const geometryBounds = expandBounds(boundsFromPoints(collectPlanPoints(floor)), PLAN_PADDING);
106→
107→  return {
108→    kind: 'plan',
109→    title: `${floor.name} Plan`,
110→    floor,
111→    bounds: geometryBounds,
