383→export function materializeSheetViewportFrames(project, sheet) {
384→  if (!sheet) return sheet;
385→
386→  const scene = buildSheetScene(project, {
387→    ...sheet,
388→    layoutTemplate: 'auto',
389→  });
390→
391→  if (!scene) return sheet;
392→
393→  const frameById = new Map(scene.viewports.map((viewport) => [viewport.id, viewport]));
394→
395→  return {
396→    ...sheet,
397→    layoutTemplate: 'manual',
398→    viewports: (sheet.viewports || []).map((viewport) => {
399→      const frame = frameById.get(viewport.id);
400→      if (!frame) {
401→        return {
402→          ...viewport,
403→          lockAutoLayout: true,
404→        };
405→      }
406→
407→      return {
408→        ...viewport,
409→        x: frame.x,
410→        y: frame.y,
411→        width: frame.width,
412→        height: frame.height,
413→        rotation: frame.rotation || 0,
414→        lockAutoLayout: true,
415→      };
416→    }),
417→  };
418→}
