case 'PHASE_DELETE': {
  const phaseId = action.phaseId;
  const nullifyPhase = (obj) =>
    obj.phaseId === phaseId ? { ...obj, phaseId: null } : obj;
  const phaseArrayKeys = [
    'walls', 'doors', 'windows', 'columns', 'beams', 'slabs',
    'stairs', 'landings', 'fixtures', 'rooms', 'railings',
  ];
  return applyProjectUpdate(state, {
    ...state.project,
    updatedAt: new Date().toISOString(),
    phases: (state.project.phases || []).filter(p => p.id !== phaseId),
    floors: state.project.floors.map(floor => {
      const updated = { ...floor };
      for (const key of phaseArrayKeys) {
        if (updated[key]) {
          updated[key] = updated[key].map(nullifyPhase);
        }
      }
      return updated;
    }),
  });
}

case 'PHASE_REORDER':
  return applyProjectUpdate(state, {
    ...state.project,
    updatedAt: new Date().toISOString(),
    phases: action.phases,
  });

